        exit(-1);
    }

    printf("Total Device found: %d\n", numPlatforms);

    for (cl_uint i = 0; i < numPlatforms; ++i) {
        status = clGetDeviceIDs(platforms[i], CL_DEVICE_TYPE_ALL, 0, NULL, &numDevices);
        if (status != CL_SUCCESS || numDevices == 0) continue;

        devices = (cl_device_id*)malloc(numDevices * sizeof(cl_device_id));
        status = clGetDeviceIDs(platforms[i], CL_DEVICE_TYPE_ALL, numDevices, devices, NULL);
        checkCLError("Getting device IDs", status);

        for (cl_uint j = 0; j < numDevices; ++j) {
            char name[256], vendor[256];
            cl_ulong globalMem;
            size_t sharedMem;
            cl_uint regsPerBlock, warpSize, maxThreadsPerBlock;
            size_t maxWorkItemSizes[3];
            size_t totalConstMem;
            cl_uint major, minor;
