            clGetDeviceInfo(devices[j], CL_DEVICE_GLOBAL_MEM_SIZE, sizeof(globalMem), &globalMem, NULL);
            clGetDeviceInfo(devices[j], CL_DEVICE_LOCAL_MEM_SIZE, sizeof(sharedMem), &sharedMem, NULL);
            regsPerBlock = 0; 
            warpSize = 0;
            clGetDeviceInfo(devices[j], CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(maxThreadsPerBlock), &maxThreadsPerBlock, NULL);
            clGetDeviceInfo(devices[j], CL_DEVICE_MAX_WORK_ITEM_sizes, sizeof(maxWorkItemSizes), maxWorkItemSizes, NULL);

            clGetDeviceInfo(devices[j], CL_DEVICE_MAX_MEM_ALLOC_SIZE, sizeof(totalConstMem), &totalConstMem, NULL); 

            char versionStr[256];
            clGetDeviceInfo(devices[j], CL_DEVICE_VERSION, sizeof(versionStr), versionStr, NULL);
